mapper.insert:
INSERT INTO freeboard (
    board_id, member_id, category, title, content, thumbnail_url
) VALUES (
    SEQ_FREEBOARD_ID.NEXTVAL, #{memberId}, #{category}, #{title}, #{content}, #{thumbnailUrl}
)

INSERT INTO freeboard_comment (
    comment_id, board_id, member_id, content
) VALUES (
    SEQ_FREEBOARD_COMMENT_ID.NEXTVAL, #{boardId}, #{memberId}, #{content}
)
